    fileprivate func hasSamePath(as other: GraphDependencyReference) -> Bool {
        switch (self, other) {
        case let (.xcframework(path1, _, _, _, _), .xcframework(path2, _, _, _, _)):
            return path1 == path2
        case let (.framework(path1, _, _, _, _, _, _, _, _), .framework(path2, _, _, _, _, _, _, _, _)):
            return path1 == path2
        default:
            return false
        }
    }
